// Drag/drop constants
export const SNAP_THRESHOLD = 120;
export const SNAP_ANIM_MS = 180;
export const TAP_MOVE_PX = 18;
export const CLICK_SUPPRESS_MS = 1200;
export const GAME_URL = "https://mynumbers.onrender.com/";
export let suppressClickUntil = 0;
export let pointerState = null;
export let scrollLocked = false;
export let autoCheckTimeout = null;
// Setters for mutable state
export function setPuzzle(p) { puzzle = p; }
export function setGameMode(m) { gameMode = m; }
export function setRushTimer(t) { rushTimer = t; }
export function setTimeRemaining(t) { timeRemaining = t; }
export function setPuzzlesSolved(n) { puzzlesSolved = n; }
export function setCurrentDifficulty(d) { currentDifficulty = d; }
export function setMaxDifficultyReached(d) { maxDifficultyReached = d; }
export function setRushIntroPlaying(b) { rushIntroPlaying = b; }
export function setSkipIntroAnimation(b) { skipIntroAnimation = b; }
export function setRushStarted(b) { rushStarted = b; }
export function setCurrentShareBlob(b) { currentShareBlob = b; }
export function setCurrentShareBlobURL(u) { currentShareBlobURL = u; }
export function setLightboardZoneIndex(i) { lightboardZoneIndex = i; }
export function setLightboardShuffledZones(z) { lightboardShuffledZones = z; }
export function setLightboardEqEls(e) { lightboardEqEls = e; }
export function setSuppressClickUntil(t) { suppressClickUntil = t; }
export function setPointerState(s) { pointerState = s; }
export function setScrollLocked(b) { scrollLocked = b; }
export function setAutoCheckTimeout(t) { autoCheckTimeout = t; }
